    "parameters": [
      {
        "name": "input",
        "description": "Text request for the one-pass subagent.",
        "required": true,
        "bindings": [
          {"kind": "POSITIONAL", "position": 1},
          {"kind": "STDIN"}
        ]
      }
    ]
  },
  "examples": [
    {
      "name": "positional-input",
      "description": {"type": "LOCALIZABLE_ASSET", "value": "Summarize a release request."},
      "args": {"input": "Summarize this release"}
    },
    {
      "name": "stdin-input",
      "description": {"type": "LOCALIZABLE_ASSET", "value": "Summarize the same request using structured input."},
      "args": {"input": "Summarize this release"}
    }
