      },
      {
        "name": "firstProvider",
        "description": "Optional provider override for the first fusion pass.",
        "externalName": "first-provider",
        "aliases": ["p1"],
        "bindings": [
          {"kind": "NAMED"}
        ]
      },
      {
        "name": "secondProvider",
