      "name": "refine-fusion",
      "type": "AGENT_RUN",
      "worker": "fusion-refiner",
      "inputs": [
        {"workType": "task", "state": "draft"}
      ],
      "outputs": [
        {"workType": "task", "state": "complete"}
      ],
      "onFailure": [
        {"workType": "task", "state": "failed"}
